import type { DMMF } from '@prisma/dmmf'

import { prismaToTsType } from './prisma-to-ts-type'

/**
 * Generates TypeScript interfaces for a single DMMF model:
 *
 * - `<Model>` — full model shape (all scalar + enum fields)
 * - `<Model>CreateInput` — fields required/optional for creation (omits auto-generated)
 * - `<Model>UpdateInput` — all fields optional (Partial-style)
 * - `<Model>WhereUniqueInput` — unique identifier fields for lookups
 */
export function generateModelInterfaces(model: DMMF.Model, enumNames: Set<string>): string {
  const scalarFields = model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')
  const sections: string[] = []

  // --- Main model interface ---
  sections.push(generateMainInterface(model.name, scalarFields, enumNames, model.documentation))

  // --- CreateInput ---
  sections.push(generateCreateInput(model.name, scalarFields, enumNames))

  // --- UpdateInput ---
  sections.push(generateUpdateInput(model.name, scalarFields, enumNames))

  // --- WhereUniqueInput ---
  sections.push(generateWhereUniqueInput(model.name, scalarFields, enumNames))

  return sections.join('\n\n')
}

function fieldTsType(field: DMMF.Field, enumNames: Set<string>): string {
  const base = field.kind === 'enum' && enumNames.has(field.type) ? field.type : prismaToTsType(field.type)
  return field.isList ? `${base}[]` : base
}

function generateMainInterface(
  modelName: string,
  fields: readonly DMMF.Field[],
  enumNames: Set<string>,
  documentation?: string,
): string {
  const lines: string[] = []
  if (documentation) {
