    if (field.isReadOnly) continue
    const tsType = fieldTsType(field, enumNames)
    const optional = !field.isRequired || field.hasDefaultValue || isAutoGenerated(field) ? '?' : ''
    const nullable = field.isRequired ? '' : ' | null'
