import fs from 'node:fs'
import os from 'node:os'
import path from 'node:path'

import type { DMMF } from '@prisma/dmmf'
import { describe, expect, test } from 'vitest'

import { generateRestClient } from '../generate-rest-client'

function makeDmmf(
  models: DMMF.Model[],
  enums: DMMF.DatamodelEnum[] = [],
): DMMF.Document {
  return {
    datamodel: { models, enums, types: [], indexes: [] },
    schema: {
      inputObjectTypes: { prisma: [] },
      outputObjectTypes: { model: [], prisma: [] },
      enumTypes: { prisma: [] },
      fieldRefTypes: {},
    },
    mappings: { modelOperations: [], otherOperations: { read: [], write: [] } },
  }
}

function makeField(overrides: Partial<DMMF.Field> & { name: string; type: string }): DMMF.Field {
  return {
    kind: 'scalar',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  }
}

function generateToString(dmmf: DMMF.Document): string {
  const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'prisma-rest-gen-'))
  generateRestClient({ dmmf, outputDir: tmpDir })
  const content = fs.readFileSync(path.join(tmpDir, 'rest-client.ts'), 'utf-8')
  fs.rmSync(tmpDir, { recursive: true, force: true })
  return content
}

describe('generateRestClient', () => {
  test('generates file header', () => {
    const dmmf = makeDmmf([])
    const output = generateToString(dmmf)
    expect(output).toContain('This file was generated by @prisma/generator-rest-api')
  })

  test('generates Fetcher type', () => {
    const dmmf = makeDmmf([])
    const output = generateToString(dmmf)
    expect(output).toContain('export type Fetcher =')
    expect(output).toContain('export type FetcherRequestInit =')
  })

  test('generates model interface with correct scalar types', () => {
    const model: DMMF.Model = {
      name: 'User',
      dbName: null,
      schema: null,
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'email', type: 'String', isUnique: true }),
        makeField({ name: 'name', type: 'String', isRequired: false }),
        makeField({ name: 'active', type: 'Boolean' }),
        makeField({ name: 'score', type: 'Float' }),
        makeField({ name: 'createdAt', type: 'DateTime', hasDefaultValue: true }),
      ],
      uniqueFields: [],
      uniqueIndexes: [],
      primaryKey: null,
    }

    const output = generateToString(makeDmmf([model]))

    expect(output).toContain('export interface User {')
    expect(output).toContain('  id: number')
    expect(output).toContain('  email: string')
    expect(output).toContain('  name?: string | null')
    expect(output).toContain('  active: boolean')
    expect(output).toContain('  score: number')
    expect(output).toContain('  createdAt: Date')
  })

  test('generates CreateInput with auto-generated fields optional', () => {
    const model: DMMF.Model = {
      name: 'Post',
      dbName: null,
      schema: null,
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'title', type: 'String' }),
        makeField({ name: 'content', type: 'String', isRequired: false }),
      ],
      uniqueFields: [],
      uniqueIndexes: [],
      primaryKey: null,
    }

    const output = generateToString(makeDmmf([model]))

    expect(output).toContain('export interface PostCreateInput {')
    // id is auto-generated (isId + hasDefaultValue), so optional
    expect(output).toContain('  id?: number')
    // title is required, no default
    expect(output).toContain('  title: string')
    // content is not required
    expect(output).toContain('  content?: string | null')
  })

  test('generates UpdateInput with all fields optional', () => {
    const model: DMMF.Model = {
      name: 'Post',
      dbName: null,
      schema: null,
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'title', type: 'String' }),
      ],
      uniqueFields: [],
      uniqueIndexes: [],
      primaryKey: null,
    }

    const output = generateToString(makeDmmf([model]))

    expect(output).toContain('export interface PostUpdateInput {')
    expect(output).toContain('  title?: string')
  })

  test('generates WhereUniqueInput from id and unique fields', () => {
    const model: DMMF.Model = {
      name: 'User',
      dbName: null,
      schema: null,
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'email', type: 'String', isUnique: true }),
        makeField({ name: 'name', type: 'String' }),
      ],
      uniqueFields: [],
      uniqueIndexes: [],
      primaryKey: null,
    }

    const output = generateToString(makeDmmf([model]))

    expect(output).toContain('export interface UserWhereUniqueInput {')
    // Multiple unique fields → each is optional
    expect(output).toContain('  id?: number')
    expect(output).toContain('  email?: string')
    // Non-unique field should not appear
    expect(output).not.toMatch(/UserWhereUniqueInput[\s\S]*?name/)
  })

  test('generates CRUD client class', () => {
    const model: DMMF.Model = {
      name: 'User',
      dbName: null,
      schema: null,
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'name', type: 'String' }),
      ],
      uniqueFields: [],
      uniqueIndexes: [],
      primaryKey: null,
    }

    const output = generateToString(makeDmmf([model]))

    expect(output).toContain('export class UserClient {')
    expect(output).toContain('async findMany(): Promise<User[]>')
    expect(output).toContain('async findUnique(where: UserWhereUniqueInput): Promise<User | null>')
    expect(output).toContain('async create(data: UserCreateInput): Promise<User>')
    expect(output).toContain('async update(where: UserWhereUniqueInput, data: UserUpdateInput): Promise<User>')
    expect(output).toContain('async delete(where: UserWhereUniqueInput): Promise<User>')
  })

  test('generates root RestApiClient wiring all models', () => {
    const userModel: DMMF.Model = {
      name: 'User',
      dbName: null,
      schema: null,
      fields: [makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true })],
      uniqueFields: [],
      uniqueIndexes: [],
      primaryKey: null,
    }
    const postModel: DMMF.Model = {
      name: 'Post',
      dbName: null,
      schema: null,
      fields: [makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true })],
      uniqueFields: [],
      uniqueIndexes: [],
      primaryKey: null,
    }

    const output = generateToString(makeDmmf([userModel, postModel]))

    expect(output).toContain('export class RestApiClient {')
    expect(output).toContain('readonly user: UserClient')
    expect(output).toContain('readonly post: PostClient')
    expect(output).toContain('this.user = new UserClient(fetcher)')
    expect(output).toContain('this.post = new PostClient(fetcher)')
  })

  test('generates enums', () => {
    const enumDef: DMMF.DatamodelEnum = {
      name: 'Role',
      values: [
        { name: 'ADMIN', dbName: null },
        { name: 'USER', dbName: null },
      ],
    }

    const model: DMMF.Model = {
      name: 'User',
      dbName: null,
      schema: null,
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'role', type: 'Role', kind: 'enum' }),
      ],
      uniqueFields: [],
      uniqueIndexes: [],
      primaryKey: null,
    }

    const output = generateToString(makeDmmf([model], [enumDef]))

    expect(output).toContain("export enum Role {")
    expect(output).toContain("  ADMIN = 'ADMIN'")
    expect(output).toContain("  USER = 'USER'")
    // Enum field in model interface should use enum type name
    expect(output).toContain('  role: Role')
  })

  test('skips relation fields in interfaces', () => {
    const model: DMMF.Model = {
      name: 'Post',
      dbName: null,
      schema: null,
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'title', type: 'String' }),
        makeField({
          name: 'author',
          type: 'User',
          kind: 'object',
          relationName: 'PostToUser',
          relationFromFields: ['authorId'],
          relationToFields: ['id'],
        }),
        makeField({ name: 'authorId', type: 'Int' }),
      ],
      uniqueFields: [],
      uniqueIndexes: [],
      primaryKey: null,
    }

    const output = generateToString(makeDmmf([model]))

    // The relation field 'author' should not appear in the interface
    expect(output).not.toMatch(/^\s+author\??:/m)
    // But the foreign key scalar field should
    expect(output).toContain('  authorId: number')
  })

  test('handles list fields', () => {
    const model: DMMF.Model = {
      name: 'User',
      dbName: null,
      schema: null,
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'tags', type: 'String', isList: true }),
