import fs from 'node:fs'
import path from 'node:path'

import type { DMMF } from '@prisma/dmmf'

import { generateCrudMethods } from './generate-crud-methods'
import { generateEnum } from './generate-enum'
import { generateModelInterfaces } from './generate-model-interfaces'

export type GenerateRestClientOptions = {
  dmmf: DMMF.Document
  outputDir: string
}

/**
 * Top-level generation entry point. Reads the DMMF, produces a single
 * `rest-client.ts` file containing interfaces, enums, CRUD client classes,
 * and a root `RestApiClient` that wires everything together.
 */
export function generateRestClient({ dmmf, outputDir }: GenerateRestClientOptions): void {
  const { models, enums } = dmmf.datamodel
  const enumNames = new Set(enums.map((e) => e.name))

  const sections: string[] = []

  // -- File header --
  sections.push(fileHeader())

  // -- Fetcher type --
  sections.push(fetcherType())

  // -- Enums --
  for (const enumDef of enums) {
    sections.push(generateEnum(enumDef))
  }

  // -- Model interfaces + CRUD clients --
  for (const model of models) {
    sections.push(generateModelInterfaces(model, enumNames))
    sections.push(generateCrudMethods(model))
  }

  // -- Root client --
  sections.push(generateRootClient(models))

  const output = sections.join('\n\n') + '\n'

  fs.mkdirSync(outputDir, { recursive: true })
  fs.writeFileSync(path.join(outputDir, 'rest-client.ts'), output, 'utf-8')
}

function fileHeader(): string {
  return [
    '// -----------------------------------------------------------------------',
    '// This file was generated by @prisma/generator-rest-api. Do not edit it.',
    '// -----------------------------------------------------------------------',
  ].join('\n')
}

function fetcherType(): string {
  return [
    'export type FetcherRequestInit = {',
    "  method: 'GET' | 'POST' | 'PATCH' | 'DELETE'",
    '  body?: unknown',
    '}',
    '',
    '/**',
    ' * A generic fetch function that consumers must provide.',
    ' * It receives a URL path and request options and must return the parsed',
    ' * JSON response body.',
    ' */',
    'export type Fetcher = (path: string, init: FetcherRequestInit) => Promise<any>',
  ].join('\n')
}

function lowerFirst(s: string): string {
  return s.charAt(0).toLowerCase() + s.slice(1)
}

function generateRootClient(models: readonly DMMF.Model[]): string {
  const lines: string[] = []

  lines.push('/**')
  lines.push(' * Root REST API client. Instantiate with a `Fetcher` function and access')
  lines.push(' * typed CRUD methods for each model via its property.')
  lines.push(' */')
  lines.push('export class RestApiClient {')

  for (const model of models) {
    lines.push(`  readonly ${lowerFirst(model.name)}: ${model.name}Client`)
  }

  lines.push('')
  lines.push('  constructor(fetcher: Fetcher) {')
  for (const model of models) {
    lines.push(`    this.${lowerFirst(model.name)} = new ${model.name}Client(fetcher)`)
  }
  lines.push('  }')
  lines.push('}')

  return lines.join('\n')
}

