import type { DMMF } from '@prisma/dmmf'

/** Generates a TypeScript string enum declaration. */
export function generateEnum(enumDef: DMMF.DatamodelEnum): string {
  const members = enumDef.values.map((v) => `  ${v.name} = '${v.name}'`).join(',\n')

  const lines: string[] = []
  if (enumDef.documentation) {
    lines.push(`/** ${enumDef.documentation} */`)
  }
  lines.push(`export enum ${enumDef.name} {`, members, '}')
  return lines.join('\n')
}

import type { DMMF } from '@prisma/dmmf'

import { prismaToTsType } from './prisma-to-ts-type'

/**
 * Generates TypeScript interfaces for a single DMMF model:
 *
 * - `<Model>` — full model shape (all scalar + enum fields)
 * - `<Model>CreateInput` — fields required/optional for creation (omits auto-generated)
 * - `<Model>UpdateInput` — all fields optional (Partial-style)
 * - `<Model>WhereUniqueInput` — unique identifier fields for lookups
 */
export function generateModelInterfaces(model: DMMF.Model, enumNames: Set<string>): string {
  const scalarFields = model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')
  const sections: string[] = []

  // --- Main model interface ---
  sections.push(generateMainInterface(model.name, scalarFields, enumNames, model.documentation))

  // --- CreateInput ---
  sections.push(generateCreateInput(model.name, scalarFields, enumNames))

  // --- UpdateInput ---
  sections.push(generateUpdateInput(model.name, scalarFields, enumNames))

  // --- WhereUniqueInput ---
  sections.push(generateWhereUniqueInput(model.name, scalarFields, enumNames))

  return sections.join('\n\n')
}

function fieldTsType(field: DMMF.Field, enumNames: Set<string>): string {
  const base = field.kind === 'enum' && enumNames.has(field.type) ? field.type : prismaToTsType(field.type)
  return field.isList ? `${base}[]` : base
}

function generateMainInterface(
  modelName: string,
  fields: readonly DMMF.Field[],
  enumNames: Set<string>,
  documentation?: string,
): string {
  const lines: string[] = []
  if (documentation) {
    lines.push(`/** ${documentation} */`)
  }
  lines.push(`export interface ${modelName} {`)
  for (const field of fields) {
    const tsType = fieldTsType(field, enumNames)
    const optional = field.isRequired ? '' : '?'
    const nullable = field.isRequired ? '' : ' | null'
    if (field.documentation) {
      lines.push(`  /** ${field.documentation} */`)
    }
    lines.push(`  ${field.name}${optional}: ${tsType}${nullable}`)
  }
  lines.push('}')
  return lines.join('\n')
}

function isAutoGenerated(field: DMMF.Field): boolean {
  return Boolean(field.isId && field.hasDefaultValue) || Boolean(field.isUpdatedAt) || Boolean(field.isGenerated)
}

function generateCreateInput(
  modelName: string,
  fields: readonly DMMF.Field[],
  enumNames: Set<string>,
): string {
  const lines: string[] = []
  lines.push(`export interface ${modelName}CreateInput {`)
  for (const field of fields) {
    if (field.isReadOnly) continue
    const tsType = fieldTsType(field, enumNames)
    const optional = !field.isRequired || field.hasDefaultValue || isAutoGenerated(field) ? '?' : ''
    const nullable = field.isRequired ? '' : ' | null'
    lines.push(`  ${field.name}${optional}: ${tsType}${nullable}`)
  }
  lines.push('}')
  return lines.join('\n')
}

function generateUpdateInput(
  modelName: string,
  fields: readonly DMMF.Field[],
  enumNames: Set<string>,
): string {
  const lines: string[] = []
  lines.push(`export interface ${modelName}UpdateInput {`)
  for (const field of fields) {
    if (field.isReadOnly) continue
    const tsType = fieldTsType(field, enumNames)
    const nullable = field.isRequired ? '' : ' | null'
    lines.push(`  ${field.name}?: ${tsType}${nullable}`)
  }
  lines.push('}')
  return lines.join('\n')
}

function generateWhereUniqueInput(
  modelName: string,
  fields: readonly DMMF.Field[],
  enumNames: Set<string>,
): string {
  const uniqueFields = fields.filter((f) => f.isId || f.isUnique)
  const lines: string[] = []
  lines.push(`export interface ${modelName}WhereUniqueInput {`)
  for (const field of uniqueFields) {
    const tsType = fieldTsType(field, enumNames)
    const optional = uniqueFields.length > 1 ? '?' : ''
    lines.push(`  ${field.name}${optional}: ${tsType}`)
  }
  lines.push('}')
  return lines.join('\n')
}

import fs from 'node:fs'
import path from 'node:path'

import type { DMMF } from '@prisma/dmmf'

import { generateCrudMethods } from './generate-crud-methods'
import { generateEnum } from './generate-enum'
import { generateModelInterfaces } from './generate-model-interfaces'

export type GenerateRestClientOptions = {
  dmmf: DMMF.Document
  outputDir: string
}

/**
 * Top-level generation entry point. Reads the DMMF, produces a single
 * `rest-client.ts` file containing interfaces, enums, CRUD client classes,
 * and a root `RestApiClient` that wires everything together.
 */
export function generateRestClient({ dmmf, outputDir }: GenerateRestClientOptions): void {
  const { models, enums } = dmmf.datamodel
  const enumNames = new Set<string>(enums.map((e) => e.name))

  const sections: string[] = []

  // -- File header --
  sections.push(fileHeader())

  // -- Fetcher type --
  sections.push(fetcherType())

  // -- Enums --
  for (const enumDef of enums) {
    sections.push(generateEnum(enumDef))
  }

  // -- Model interfaces + CRUD clients --
  for (const model of models) {
    sections.push(generateModelInterfaces(model, enumNames))
    sections.push(generateCrudMethods(model))
  }

  // -- Root client --
  sections.push(generateRootClient(models))

  const output = sections.join('\n\n') + '\n'

  fs.mkdirSync(outputDir, { recursive: true })
  fs.writeFileSync(path.join(outputDir, 'rest-client.ts'), output, 'utf-8')
}

function fileHeader(): string {
  return [
    '// -----------------------------------------------------------------------',
    '// This file was generated by @prisma/generator-rest-api. Do not edit it.',
    '// -----------------------------------------------------------------------',
  ].join('\n')
}

function fetcherType(): string {
  return [
    'export type FetcherRequestInit = {',
    "  method: 'GET' | 'POST' | 'PATCH' | 'DELETE'",
    '  body?: unknown',
    '}',
    '',
    '/**',
    ' * A generic fetch function that consumers must provide.',
    ' * It receives a URL path and request options and must return the parsed',
    ' * JSON response body.',
    ' */',
    'export type Fetcher = (path: string, init: FetcherRequestInit) => Promise<any>',
  ].join('\n')
}

function lowerFirst(s: string): string {
  return s.charAt(0).toLowerCase() + s.slice(1)
}

function generateRootClient(models: readonly DMMF.Model[]): string {
  const lines: string[] = []

  lines.push('/**')
  lines.push(' * Root REST API client. Instantiate with a `Fetcher` function and access')
  lines.push(' * typed CRUD methods for each model via its property.')
  lines.push(' */')
  lines.push('export class RestApiClient {')

  for (const model of models) {
    lines.push(`  readonly ${lowerFirst(model.name)}: ${model.name}Client`)
  }

  lines.push('')
  lines.push('  constructor(fetcher: Fetcher) {')
  for (const model of models) {
    lines.push(`    this.${lowerFirst(model.name)} = new ${model.name}Client(fetcher)`)
  }
  lines.push('  }')
  lines.push('}')

  return lines.join('\n')
}

import fs from 'node:fs'
import os from 'node:os'
import path from 'node:path'

import type { DMMF } from '@prisma/dmmf'
import { describe, expect, test } from 'vitest'

import { generateRestClient } from '../generate-rest-client'

function makeDmmf(
  models: DMMF.Model[],
  enums: DMMF.DatamodelEnum[] = [],
): DMMF.Document {
  return {
    datamodel: { models, enums, types: [], indexes: [] },
    schema: {
      inputObjectTypes: { prisma: [] },
      outputObjectTypes: { model: [], prisma: [] },
      enumTypes: { prisma: [] },
      fieldRefTypes: {},
    },
    mappings: { modelOperations: [], otherOperations: { read: [], write: [] } },
  }
}

function makeField(overrides: Partial<DMMF.Field> & { name: string; type: string }): DMMF.Field {
  return {
    kind: 'scalar',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  }
}

function generateToString(dmmf: DMMF.Document): string {
  const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'prisma-rest-gen-'))
  generateRestClient({ dmmf, outputDir: tmpDir })
  const content = fs.readFileSync(path.join(tmpDir, 'rest-client.ts'), 'utf-8')
  fs.rmSync(tmpDir, { recursive: true, force: true })
  return content
}

describe('generateRestClient', () => {
  test('generates file header', () => {
    const dmmf = makeDmmf([])
    const output = generateToString(dmmf)
    expect(output).toContain('This file was generated by @prisma/generator-rest-api')
  })

  test('generates Fetcher type', () => {
    const dmmf = makeDmmf([])
    const output = generateToString(dmmf)
    expect(output).toContain('export type Fetcher =')
    expect(output).toContain('export type FetcherRequestInit =')
  })

  test('generates model interface with correct scalar types', () => {
    const model: DMMF.Model = {
      name: 'User',
      dbName: null,
      schema: null,
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'email', type: 'String', isUnique: true }),
        makeField({ name: 'name', type: 'String', isRequired: false }),
        makeField({ name: 'active', type: 'Boolean' }),
        makeField({ name: 'score', type: 'Float' }),
        makeField({ name: 'createdAt', type: 'DateTime', hasDefaultValue: true }),
      ],
      uniqueFields: [],
      uniqueIndexes: [],
      primaryKey: null,
    }

    const output = generateToString(makeDmmf([model]))

    expect(output).toContain('export interface User {')
    expect(output).toContain('  id: number')
    expect(output).toContain('  email: string')
    expect(output).toContain('  name?: string | null')
    expect(output).toContain('  active: boolean')
    expect(output).toContain('  score: number')
    expect(output).toContain('  createdAt: Date')
  })

  test('generates CreateInput with auto-generated fields optional', () => {
    const model: DMMF.Model = {
      name: 'Post',
      dbName: null,
      schema: null,
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'title', type: 'String' }),
        makeField({ name: 'content', type: 'String', isRequired: false }),
      ],
      uniqueFields: [],
      uniqueIndexes: [],
      primaryKey: null,
    }

    const output = generateToString(makeDmmf([model]))

    expect(output).toContain('export interface PostCreateInput {')
    // id is auto-generated (isId + hasDefaultValue), so optional
    expect(output).toContain('  id?: number')
    // title is required, no default
    expect(output).toContain('  title: string')
    // content is not required
    expect(output).toContain('  content?: string | null')
  })

  test('generates UpdateInput with all fields optional', () => {
    const model: DMMF.Model = {
      name: 'Post',
      dbName: null,
      schema: null,
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'title', type: 'String' }),
      ],
      uniqueFields: [],
      uniqueIndexes: [],
      primaryKey: null,
    }

    const output = generateToString(makeDmmf([model]))

    expect(output).toContain('export interface PostUpdateInput {')
    expect(output).toContain('  title?: string')
  })

  test('generates WhereUniqueInput from id and unique fields', () => {
    const model: DMMF.Model = {
      name: 'User',
      dbName: null,
      schema: null,
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'email', type: 'String', isUnique: true }),
        makeField({ name: 'name', type: 'String' }),
      ],
      uniqueFields: [],
      uniqueIndexes: [],
      primaryKey: null,
    }

    const output = generateToString(makeDmmf([model]))

    expect(output).toContain('export interface UserWhereUniqueInput {')
    // Multiple unique fields → each is optional
    expect(output).toContain('  id?: number')
    expect(output).toContain('  email?: string')
    // Non-unique field should not appear
    expect(output).not.toMatch(/UserWhereUniqueInput[\s\S]*?name/)
  })

  test('generates CRUD client class', () => {
    const model: DMMF.Model = {
      name: 'User',
      dbName: null,
      schema: null,
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'name', type: 'String' }),
      ],
      uniqueFields: [],
      uniqueIndexes: [],
      primaryKey: null,
    }

    const output = generateToString(makeDmmf([model]))

    expect(output).toContain('export class UserClient {')
    expect(output).toContain('async findMany(): Promise<User[]>')
    expect(output).toContain('async findUnique(where: UserWhereUniqueInput): Promise<User | null>')
    expect(output).toContain('async create(data: UserCreateInput): Promise<User>')
    expect(output).toContain('async update(where: UserWhereUniqueInput, data: UserUpdateInput): Promise<User>')
    expect(output).toContain('async delete(where: UserWhereUniqueInput): Promise<User>')
  })

  test('generates root RestApiClient wiring all models', () => {
    const userModel: DMMF.Model = {
      name: 'User',
      dbName: null,
      schema: null,
      fields: [makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true })],
      uniqueFields: [],
      uniqueIndexes: [],
      primaryKey: null,
    }
    const postModel: DMMF.Model = {
      name: 'Post',
      dbName: null,
      schema: null,
      fields: [makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true })],
      uniqueFields: [],
      uniqueIndexes: [],
      primaryKey: null,
    }

    const output = generateToString(makeDmmf([userModel, postModel]))

    expect(output).toContain('export class RestApiClient {')
    expect(output).toContain('readonly user: UserClient')
    expect(output).toContain('readonly post: PostClient')
    expect(output).toContain('this.user = new UserClient(fetcher)')
    expect(output).toContain('this.post = new PostClient(fetcher)')
  })

  test('generates enums', () => {
    const enumDef: DMMF.DatamodelEnum = {
      name: 'Role',
      values: [
        { name: 'ADMIN', dbName: null },
        { name: 'USER', dbName: null },
      ],
    }

    const model: DMMF.Model = {
      name: 'User',
      dbName: null,
      schema: null,
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'role', type: 'Role', kind: 'enum' }),
      ],
      uniqueFields: [],
      uniqueIndexes: [],
      primaryKey: null,
    }

    const output = generateToString(makeDmmf([model], [enumDef]))

    expect(output).toContain("export enum Role {")
    expect(output).toContain("  ADMIN = 'ADMIN'")
    expect(output).toContain("  USER = 'USER'")
    // Enum field in model interface should use enum type name
    expect(output).toContain('  role: Role')
  })

  test('skips relation fields in interfaces', () => {
    const model: DMMF.Model = {
      name: 'Post',
      dbName: null,
      schema: null,
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'title', type: 'String' }),
        makeField({
          name: 'author',
          type: 'User',
          kind: 'object',
          relationName: 'PostToUser',
          relationFromFields: ['authorId'],
          relationToFields: ['id'],
        }),
        makeField({ name: 'authorId', type: 'Int' }),
      ],
      uniqueFields: [],
      uniqueIndexes: [],
      primaryKey: null,
    }

    const output = generateToString(makeDmmf([model]))

    // The relation field 'author' should not appear in the interface
    expect(output).not.toMatch(/^\s+author\??:/m)
    // But the foreign key scalar field should
    expect(output).toContain('  authorId: number')
  })

  test('handles list fields', () => {
    const model: DMMF.Model = {
      name: 'User',
      dbName: null,
      schema: null,
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'tags', type: 'String', isList: true }),
      ],
      uniqueFields: [],
      uniqueIndexes: [],
      primaryKey: null,
    }

    const output = generateToString(makeDmmf([model]))

    expect(output).toContain('  tags: string[]')
  })

  test('handles BigInt, Decimal, Bytes, Json types', () => {
    const model: DMMF.Model = {
      name: 'Record',
      dbName: null,
      schema: null,
      fields: [
        makeField({ name: 'id', type: 'BigInt', isId: true, hasDefaultValue: true }),
        makeField({ name: 'amount', type: 'Decimal' }),
        makeField({ name: 'data', type: 'Bytes' }),
        makeField({ name: 'meta', type: 'Json' }),
      ],
      uniqueFields: [],
      uniqueIndexes: [],
      primaryKey: null,
    }

    const output = generateToString(makeDmmf([model]))

    expect(output).toContain('  id: bigint')
    expect(output).toContain('  amount: number')
    expect(output).toContain('  data: Uint8Array')
    expect(output).toContain('  meta: unknown')
  })

  test('uses default base path from lowercased model name', () => {
    const model: DMMF.Model = {
      name: 'BlogPost',
      dbName: null,
      schema: null,
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      ],
      uniqueFields: [],
      uniqueIndexes: [],
      primaryKey: null,
    }

    const output = generateToString(makeDmmf([model]))

    expect(output).toContain("basePath = '/blogPost'")
  })

  test('excludes readOnly fields from CreateInput and UpdateInput', () => {
    const model: DMMF.Model = {
      name: 'User',
      dbName: null,
      schema: null,
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'name', type: 'String' }),
        makeField({ name: 'computed', type: 'String', isReadOnly: true }),
      ],
      uniqueFields: [],
      uniqueIndexes: [],
      primaryKey: null,
    }

    const output = generateToString(makeDmmf([model]))

    // computed should appear in the main interface
    expect(output).toMatch(/export interface User \{[\s\S]*?computed: string/)
    // but NOT in create or update inputs
    expect(output).not.toMatch(/UserCreateInput[\s\S]*?computed/)
    expect(output).not.toMatch(/UserUpdateInput[\s\S]*?computed/)
  })
})

